const d = $input.first().json;

const ref = 'NEO-' + (d.session_id || '000000').slice(-6).toUpperCase();
const dateGen = new Date().toLocaleDateString('fr-FR', { day: '2-digit', month: 'long', year: 'numeric' });
const dateDep = d.date_depart
  ? new Date(d.date_depart).toLocaleDateString('fr-FR', { day: '2-digit', month: 'long', year: 'numeric' })
  : '—';

const lignesHTML = (d.lignes_detail || '').split('\n')
  .filter(l => l.trim())
  .map(l => {
    const isTotal = l.startsWith('MONTANT');
    const bg = isTotal ? '#EEF2FF' : (l.includes('Saisonnalité') || l.includes('Date') || l.includes('Capacité') ? '#F9FAFB' : '#FFFFFF');
    const color = isTotal ? '#1E40AF' : '#374151';
    const weight = isTotal ? '700' : '400';
    return `<tr><td style="padding:6px 14px;font-size:12px;background:${bg};color:${color};font-weight:${weight};border-bottom:1px solid #F3F4F6;">${l}</td></tr>`;
  }).join('');

const ht  = Number(d.montant_ht ).toLocaleString('fr-FR', { minimumFractionDigits: 2 });
const ttc = Number(d.montant_ttc).toLocaleString('fr-FR', { minimumFractionDigits: 2 });

const html = `<!DOCTYPE html>
<html lang="fr"><head><meta charset="UTF-8"><style>
* { margin:0;padding:0;box-sizing:border-box; }
body { font-family:Arial,Helvetica,sans-serif;color:#1F2937;background:#fff;padding:40px;font-size:14px; }
.header { display:flex;justify-content:space-between;align-items:flex-start;padding-bottom:20px;border-bottom:3px solid #1E40AF;margin-bottom:28px; }
.logo { font-size:28px;font-weight:800;color:#1E40AF;letter-spacing:-1px; }
.logo span { color:#F59E0B; }
.logo-sub { font-size:12px;color:#6B7280;margin-top:3px; }
.ref-block { text-align:right; }
.ref-num { font-size:22px;font-weight:700;color:#1E40AF; }
.ref-date { font-size:12px;color:#6B7280;margin-top:3px; }
.grid { display:grid;grid-template-columns:1fr 1fr;gap:20px;margin-bottom:20px; }
.card { background:#F8FAFC;border:1px solid #E2E8F0;border-radius:8px;padding:16px; }
.card-label { font-size:10px;font-weight:700;text-transform:uppercase;letter-spacing:1px;color:#9CA3AF;margin-bottom:6px; }
.card-value { font-size:15px;font-weight:600;color:#1F2937; }
.card-sub { font-size:12px;color:#6B7280;margin-top:3px; }
.route { display:flex;align-items:center;gap:10px; }
.city { font-size:17px;font-weight:700;color:#1E40AF; }
.arrow { font-size:18px;color:#9CA3AF; }
table { width:100%;border-collapse:collapse; }
.section-title { font-size:11px;font-weight:700;text-transform:uppercase;letter-spacing:1px;color:#9CA3AF;margin-bottom:8px;margin-top:20px; }
.price-box { background:linear-gradient(135deg,#1E40AF 0%,#3B82F6 100%);color:white;border-radius:12px;padding:24px 28px;margin:24px 0; }
.price-ht { font-size:14px;opacity:.85; }
.price-ttc { font-size:38px;font-weight:800;margin:8px 0 4px; }
.price-note { font-size:12px;opacity:.7; }
.validity { text-align:center;font-size:12px;color:#9CA3AF;margin-bottom:16px; }
.cta { background:#F59E0B;color:white;text-align:center;padding:14px 20px;border-radius:8px;font-weight:700;font-size:14px; }
.footer { margin-top:36px;padding-top:16px;border-top:1px solid #E5E7EB;display:flex;justify-content:space-between;font-size:11px;color:#9CA3AF; }
</style></head>
<body>
<div class="header">
  <div><div class="logo">Neo<span>travel</span></div><div class="logo-sub">Location d'autocars avec chauffeur</div></div>
  <div class="ref-block"><div class="ref-num">DEVIS ${ref}</div><div class="ref-date">Établi le ${dateGen} · Valable 30 jours</div></div>
</div>
<div class="grid">
  <div class="card"><div class="card-label">Client</div><div class="card-value" style="font-size:17px;">${d.nom_prospect || '—'}</div><div class="card-sub">${d.email || ''}</div></div>
  <div class="card"><div class="card-label">Trajet</div><div class="route"><div class="city">${d.ville_depart || '—'}</div><div class="arrow">${d.aller_retour ? '⇄' : '→'}</div><div class="city">${d.ville_destination || '—'}</div></div><div class="card-sub" style="margin-top:8px;">Départ : <strong>${dateDep}</strong></div></div>
</div>
<div class="grid">
  <div class="card"><div class="card-label">Passagers</div><div class="card-value">${d.nb_passagers || '—'} personnes</div></div>
  <div class="card"><div class="card-label">Type</div><div class="card-value">${d.aller_retour ? 'Aller / Retour' : 'Aller simple'}</div></div>
</div>
<div class="section-title">Détail tarifaire</div>
<table>${lignesHTML}</table>
<div class="price-box"><div class="price-ht">Montant HT : ${ht} €</div><div class="price-ttc">${ttc} € TTC</div><div class="price-note">Prix tout compris · Chauffeur inclus · Sans frais cachés</div></div>
<div class="validity">Ce devis est valable 30 jours à compter de sa date d'émission.</div>
<div class="cta">Pour accepter ce devis : répondez directement à cet email</div>
<div class="footer"><div>Neotravel SAS · contact@neotravel.fr</div><div>Réf. ${ref}</div></div>
</body></html>`;

const BASE_URL = 'https://YOUR-APP.vercel.app'; const pdf_url = BASE_URL + '/api/devis/pdf?session_id=' + (d.session_id || ''); return [{ json: { ...d, html, ref, pdf_url } }];

const binaryData = await this.helpers.getBinaryDataBuffer(0, 'data');
const base64 = binaryData.toString('base64');

const entree = $('When Executed by Another Workflow').first().json;

return [{
  json: {
    ...entree,
    pdf_base64: base64,
    pdf_content_type: 'application/pdf',
    pdf_filename: `devis-${(entree.session_id || '000000').slice(-6).toUpperCase()}.pdf`
  }
}];
